    contract: { contractId: "ctr-nc2", arrCents: 9_000_000, renewalDate: "2026-10-31", supportPlan: "platinum" },
    contacts: [{ contactId: "ct-nc2", role: "Finance", email: "fin@bluewave.test" }],
